import React from 'react';

const Testimonials = () => (
    <section className="py-20 px-8 bg-gray-950 text-white">
        <h2 className="text-3xl font-bold text-center mb-10">Apa Kata Mereka?</h2>
        <div className="max-w-4xl mx-auto text-center italic text-gray-400">
            "Berkat PasukanYerusSolo, saya mendapatkan pekerjaan impian saya di Solo hanya dalam waktu 2 minggu. Prosesnya sangat mudah!"
            <p className="mt-4 font-bold text-orange-500 not-italic">- Budi, Fullstack Developer</p>
        </div>
    </section>
);
export default Testimonials;
